module RefModule(
    input               clk,
    input               load,
    input       [1:0]   ena,
    input       [99:0]  data,
    output  reg [99:0]  q
);reg         [99:0]  unused_q_next;
    always @(posedge clk) begin
            q <= unused_q_next;
    end

    always @(*) begin
        if (load)
            unused_q_next = data;
        else
            case (ena)
            2'b01   : unused_q_next = {q[0], q[99:1]};
            2'b10   : unused_q_next = {q[98:0], q[99]};
            default : unused_q_next = q;
            endcase
    end

endmodule
